#!/usr/bin/env Rscript
# verify_predictions.R
#
# Load fixtures generated by generate_predictions.py, reproduce the same
# predictions in R with the same seed and parameters, then compare.
# Exits non-zero if any parity check fails.
#
# Usage:
#   Rscript test/cross_language/verify_predictions.R [fixture-dir]
#
# For local dev with devtools::load_all instead of an installed package:
#   STOCHTREE_R_DEV=1 Rscript test/cross_language/verify_predictions.R [fixture-dir]
#
# Fixture schema: see generate_predictions.py

if (nzchar(Sys.getenv("STOCHTREE_R_DEV"))) {
  repo_root <- Sys.getenv("STOCHTREE_REPO_ROOT", ".")
  devtools::load_all(repo_root, quiet = TRUE)
} else {
  library(stochtree)
}
library(jsonlite)

args <- commandArgs(trailingOnly = TRUE)
fixture_dir <- if (length(args) > 0) args[[1]] else "test/cross_language/fixtures"

# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

read_matrix <- function(path) {
  as.matrix(read.table(path, sep = ",", header = FALSE))
}

check_parity <- function(label, python_mat, r_mat, tol = 1e-10) {
  stopifnot(identical(dim(python_mat), dim(r_mat)))
  max_diff <- max(abs(python_mat - r_mat))
  if (max_diff <= tol) {
    cat(sprintf("  PASS  %-40s max|diff| = %.2e\n", label, max_diff))
  } else {
    cat(sprintf("  FAIL  %-40s max|diff| = %.2e  (tol %.2e)\n",
                label, max_diff, tol))
    stop(paste("Parity check failed:", label))
  }
}

scenario_exists <- function(fixture_dir, name) {
  file.exists(file.path(fixture_dir, paste0(name, ".json")))
}

# ---------------------------------------------------------------------------
# Scenario: bart_basic
# ---------------------------------------------------------------------------

scenario_bart_basic <- function(fixture_dir) {
  if (!scenario_exists(fixture_dir, "bart_basic")) {
    message("Skipping bart_basic — no fixture found")
    return(invisible(NULL))
  }

  cat("--- bart_basic ---\n")
  meta <- fromJSON(file.path(fixture_dir, "bart_basic.json"))

  # Load the exact same data Python used (written to fixture by generator)
  X_train <- read_matrix(file.path(fixture_dir, "bart_basic_X_train.csv"))
  y_train <- as.numeric(read_matrix(file.path(fixture_dir, "bart_basic_y_train.csv")))
  X_test  <- read_matrix(file.path(fixture_dir, "bart_basic_X_test.csv"))

  # Fit with the same hyperparameters and seed
  model <- bart(
    X_train = X_train, y_train = y_train,
    num_gfr = meta$num_gfr,
    num_burnin = meta$num_burnin,
    num_mcmc = meta$num_mcmc,
    general_params = list(random_seed = meta$seed)
  )

  py_yhat_train <- read_matrix(file.path(fixture_dir, "bart_basic_yhat_train.csv"))
  r_yhat_train  <- predict(model, X_train, terms = "y_hat")
  check_parity("bart_basic / yhat_train", py_yhat_train, r_yhat_train)

  py_yhat_test <- read_matrix(file.path(fixture_dir, "bart_basic_yhat_test.csv"))
  r_yhat_test  <- predict(model, X_test, terms = "y_hat")
  check_parity("bart_basic / yhat_test", py_yhat_test, r_yhat_test)
}


# ---------------------------------------------------------------------------
# Scenario: bcf_basic
# ---------------------------------------------------------------------------

scenario_bcf_basic <- function(fixture_dir) {
  if (!scenario_exists(fixture_dir, "bcf_basic")) {
    message("Skipping bcf_basic — no fixture found")
    return(invisible(NULL))
  }

  cat("--- bcf_basic ---\n")
  meta <- fromJSON(file.path(fixture_dir, "bcf_basic.json"))

  X_train  <- read_matrix(file.path(fixture_dir, "bcf_basic_X_train.csv"))
  Z_train  <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_basic_Z_train.csv")))
  y_train  <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_basic_y_train.csv")))
  pi_train <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_basic_pi_train.csv")))
  X_test   <- read_matrix(file.path(fixture_dir, "bcf_basic_X_test.csv"))
  Z_test   <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_basic_Z_test.csv")))
  pi_test  <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_basic_pi_test.csv")))

  model <- bcf(
    X_train = X_train, Z_train = Z_train,
    y_train = y_train, propensity_train = pi_train,
    num_gfr = meta$num_gfr,
    num_burnin = meta$num_burnin,
    num_mcmc = meta$num_mcmc,
    general_params = list(random_seed = meta$seed)
  )

  for (split in c("train", "test")) {
    X_s  <- if (split == "train") X_train else X_test
    Z_s  <- if (split == "train") Z_train else Z_test
    pi_s <- if (split == "train") pi_train else pi_test

    check_parity(
      sprintf("bcf_basic / yhat_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_basic_yhat_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "y_hat")
    )
    check_parity(
      sprintf("bcf_basic / tau_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_basic_tau_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "tau")
    )
    check_parity(
      sprintf("bcf_basic / mu_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_basic_mu_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "mu")
    )
  }
}


# ---------------------------------------------------------------------------
# Scenario: bart_rfx
# ---------------------------------------------------------------------------

scenario_bart_rfx <- function(fixture_dir) {
  if (!scenario_exists(fixture_dir, "bart_rfx")) {
    message("Skipping bart_rfx — no fixture found")
    return(invisible(NULL))
  }

  cat("--- bart_rfx ---\n")
  meta <- fromJSON(file.path(fixture_dir, "bart_rfx.json"))

  X_train  <- read_matrix(file.path(fixture_dir, "bart_rfx_X_train.csv"))
  y_train  <- as.numeric(read_matrix(file.path(fixture_dir, "bart_rfx_y_train.csv")))
  g_train  <- as.integer(as.numeric(read_matrix(file.path(fixture_dir, "bart_rfx_group_train.csv"))))
  X_test   <- read_matrix(file.path(fixture_dir, "bart_rfx_X_test.csv"))
  g_test   <- as.integer(as.numeric(read_matrix(file.path(fixture_dir, "bart_rfx_group_test.csv"))))

  model <- bart(
    X_train = X_train, y_train = y_train,
    rfx_group_ids_train = g_train,
    num_gfr = meta$num_gfr,
    num_burnin = meta$num_burnin,
    num_mcmc = meta$num_mcmc,
    general_params = list(random_seed = meta$seed),
    random_effects_params = list(model_spec = "intercept_only")
  )

  for (split in c("train", "test")) {
    X_s <- if (split == "train") X_train else X_test
    g_s <- if (split == "train") g_train else g_test

    check_parity(
      sprintf("bart_rfx / yhat_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bart_rfx_yhat_%s.csv", split))),
      predict(model, X_s, rfx_group_ids = g_s, terms = "y_hat")
    )
    check_parity(
      sprintf("bart_rfx / rfx_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bart_rfx_rfx_%s.csv", split))),
      predict(model, X_s, rfx_group_ids = g_s, terms = "rfx")
    )
  }
}


# ---------------------------------------------------------------------------
# Scenario: bcf_varforest
# ---------------------------------------------------------------------------

scenario_bcf_varforest <- function(fixture_dir) {
  if (!scenario_exists(fixture_dir, "bcf_varforest")) {
    message("Skipping bcf_varforest — no fixture found")
    return(invisible(NULL))
  }

  cat("--- bcf_varforest ---\n")
  meta <- fromJSON(file.path(fixture_dir, "bcf_varforest.json"))

  X_train  <- read_matrix(file.path(fixture_dir, "bcf_varforest_X_train.csv"))
  Z_train  <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_varforest_Z_train.csv")))
  y_train  <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_varforest_y_train.csv")))
  pi_train <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_varforest_pi_train.csv")))
  X_test   <- read_matrix(file.path(fixture_dir, "bcf_varforest_X_test.csv"))
  Z_test   <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_varforest_Z_test.csv")))
  pi_test  <- as.numeric(read_matrix(file.path(fixture_dir, "bcf_varforest_pi_test.csv")))

  model <- bcf(
    X_train = X_train, Z_train = Z_train,
    y_train = y_train, propensity_train = pi_train,
    num_gfr = meta$num_gfr,
    num_burnin = meta$num_burnin,
    num_mcmc = meta$num_mcmc,
    general_params = list(random_seed = meta$seed),
    variance_forest_params = list(num_trees = meta$params$num_trees_variance)
  )

  for (split in c("train", "test")) {
    X_s  <- if (split == "train") X_train else X_test
    Z_s  <- if (split == "train") Z_train else Z_test
    pi_s <- if (split == "train") pi_train else pi_test

    check_parity(
      sprintf("bcf_varforest / yhat_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_varforest_yhat_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "y_hat")
    )
    check_parity(
      sprintf("bcf_varforest / tau_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_varforest_tau_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "tau")
    )
    check_parity(
      sprintf("bcf_varforest / mu_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_varforest_mu_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "mu")
    )
    check_parity(
      sprintf("bcf_varforest / sigma2x_%s", split),
      read_matrix(file.path(fixture_dir, sprintf("bcf_varforest_sigma2x_%s.csv", split))),
      predict(model, X_s, Z_s, propensity = pi_s, terms = "variance_forest")
    )
  }
}


# ---------------------------------------------------------------------------
# Dispatch
# ---------------------------------------------------------------------------

scenario_bart_basic(fixture_dir)
scenario_bcf_basic(fixture_dir)
scenario_bart_rfx(fixture_dir)
scenario_bcf_varforest(fixture_dir)

cat("Cross-language parity check complete\n")
